import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.Nx1zvZTu.js";const u=JSON.parse('{"title":"The API server","description":"","frontmatter":{},"headers":[],"relativePath":"guide/server.md","filePath":"guide/server.md"}'),r={name:"guide/server.md"};function d(i,e,c,n,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-api-server" tabindex="-1">The API server <a class="header-anchor" href="#the-api-server" aria-label="Permalink to &quot;The API server&quot;">​</a></h1><p>machinable ships an HTTP + WebSocket server that exposes a project&#39;s interfaces to remote clients: a JSON control plane, a binary data plane, the config/identity <a href="./storage.html">index</a> with search, and the <a href="./execution.html">execution</a> lifecycle. Each interface decides what its bytes and method calls mean; the server stays use-case agnostic. (The <a href="/mcp/overview.html">MCP</a> is a curated, agent-facing facade over this same surface.)</p><h2 id="launching" tabindex="-1">Launching <a class="header-anchor" href="#launching" aria-label="Permalink to &quot;Launching&quot;">​</a></h2><p>The server is itself an interface (<code>machinable.server</code>). Launch it with the <a href="./cli.html">CLI</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">machinable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> machinable.server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project=&quot;/path/to/project&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --launch</span></span></code></pre></div><p>Its <code>Config</code> controls the bind and the security surface:</p><table tabindex="0"><thead><tr><th>Field</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>host</code> / <code>port</code></td><td><code>127.0.0.1</code> / <code>8000</code></td><td>bind address</td></tr><tr><td><code>console</code></td><td><code>None</code> (auto)</td><td>attach the <a href="#the-console">console</a> when launched from a terminal</td></tr><tr><td><code>api_token</code></td><td><code>None</code></td><td>bearer token required for requests</td></tr><tr><td><code>project</code></td><td><code>None</code></td><td>the default project a request binds to</td></tr><tr><td><code>project_roots</code></td><td><code>None</code></td><td>extra roots that may be opened per request</td></tr><tr><td><code>enable_source_api</code></td><td><code>False</code></td><td>allow writing project <code>.py</code> files (remote code execution, off by default)</td></tr><tr><td><code>source_token</code></td><td><code>None</code></td><td>token required for the source-editing API</td></tr></tbody></table><h2 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h2><p>A request binds to a project and a user:</p><ul><li><code>X-Machinable-Project</code> (or <code>?project=</code>): the target project, restricted to the server&#39;s allowlist; defaults to the launch project.</li><li><code>X-Machinable-User</code>: attributes created interfaces (<code>created_by</code>); defaults to the OS user.</li></ul><h2 id="what-it-exposes" tabindex="-1">What it exposes <a class="header-anchor" href="#what-it-exposes" aria-label="Permalink to &quot;What it exposes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Family</th><th>Examples</th><th>Purpose</th></tr></thead><tbody><tr><td>Interfaces</td><td><code>POST /v1/interfaces</code>, <code>/search</code>, <code>/resolve</code>, <code>/{uuid}/provenance</code> <code>/data</code> <code>/related</code></td><td>create, search, dry-run, inspect</td></tr><tr><td>Executions</td><td><code>POST /v1/executions</code>, <code>GET /{uuid}</code>, <code>/output</code></td><td>run lifecycle + output</td></tr><tr><td>Project</td><td><code>GET /v1/project[/{module}]</code>, <code>/remotes</code></td><td>module discovery + schema reflection</td></tr><tr><td>Source</td><td><code>GET/PUT/DELETE /v1/source/{path}</code></td><td>the opt-in, token-gated source-editing API</td></tr></tbody></table><p>Config reflection is first-class: <code>GET /v1/project/{module}</code> returns the config fields and the <a href="./versions.html">version-method vocabulary</a> (signatures + docstrings), and <code>POST /v1/interfaces/resolve</code> dry-runs a compact version to its resolved config and CLI without materializing.</p><h2 id="the-console" tabindex="-1">The console <a class="header-anchor" href="#the-console" aria-label="Permalink to &quot;The console&quot;">​</a></h2><p><code>machinable console</code> attaches a terminal UI to a running server, local or remote. It is a pure API client, so everything it shows travels through the same contract as any other client:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;machinable[console]&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">machinable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> console</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                              # http://127.0.0.1:8000</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">machinable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> console</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://cluster:8000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SECRET</span></span></code></pre></div><p>The console browses and filters the record catalog, opens a record to inspect its resolved config, run history, and stored files, follows a live run&#39;s output, and cancels runs (<code>y</code> copies the record&#39;s CLI reproduction command). A server launched from a terminal attaches the console automatically when it is installed; set <code>console=true</code> to require it (launching fails with an install hint when it is missing) or <code>console=false</code> for a headless server.</p><p>Beyond browsing, the console drives the full loop:</p><ul><li><strong>Launch pad</strong> (<code>n</code>): pick a module, see its config fields and <code>~version</code> vocabulary, and type a version exactly like the <a href="./cli.html">CLI</a> (<code>~sgd lr=0.1 nested.k=2</code>). The preview resolves live, so typos surface as precise unknown-key errors, and an identity badge shows whether this configuration is a <code>draft</code> (launching runs it) or already <code>cached</code> (launching opens the existing record) before anything executes.</li><li><strong>Provenance</strong> (record detail tab): the record&#39;s provenance graph as a navigable tree of derivation, runs, and manifest edges; selecting a node jumps to that record.</li><li><strong>Call</strong> (record detail tab): invoke a method with the shared <code>method(args)</code> grammar (e.g. <code>summary(top=3)</code>) and read the returned value, with the equivalent <code>machinable … --method(args)</code> command shown for reproduction.</li><li><strong>Remotes</strong> (<code>R</code>): the project&#39;s declared remote modules, with the <a href="./storage.html#remotes-shareable-interfaces">inspect-before-import</a> workflow.</li><li><code>ctrl+p</code> opens the command palette; <code>?</code> shows the key reference.</li></ul><h2 id="the-full-contract" tabindex="-1">The full contract <a class="header-anchor" href="#the-full-contract" aria-label="Permalink to &quot;The full contract&quot;">​</a></h2><p>The server documents itself, so there is no static copy to keep in sync:</p><ul><li><strong>REST/OpenAPI</strong>: <code>GET /openapi.json</code> and the interactive <code>/docs</code>.</li><li><strong>WebSocket protocol</strong>: <code>GET /v1/protocol</code> returns a machine-readable description of the connect / call / stream / chunk-upload / event frames, which OpenAPI can&#39;t model.</li><li>Regenerate a markdown snapshot any time with <code>python -m machinable.api.docs</code>.</li></ul><p>For agent-facing usage, prefer the <a href="/mcp/overview.html">MCP server</a>, which wraps this API as curated tools, resources, and prompts.</p>`,23)])])}const g=t(r,[["render",d]]);export{u as __pageData,g as default};
